import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null || line.isEmpty()) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder sb = new StringBuilder();
        for (int t = 0; t < T; t++) {
            String name = br.readLine();
            String idLine = br.readLine();
            String salaryLine = br.readLine();
            long employee_id = Long.parseLong(idLine.trim());
            double salary = Double.parseDouble(salaryLine.trim());
            sb.append("Name: ").append(name)
              .append(" ID: ").append(employee_id)
              .append(" Salary: ")
              .append(String.format(java.util.Locale.US, "%.2f", salary));
            if (t + 1 < T) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

